<template>
  <div class="login">
    <div class="title">
      <h2><p>登 录</p></h2>
    </div>
    <el-form
      :model="ruleForm"
      status-icon
      :rules="rules"
      ref="ruleForm"
      label-width="100px"
      class="demo-ruleForm"
    >
      <el-form-item label="用户名" prop="userName">
        <el-input
          @keydown.enter.native="login"
          v-model="ruleForm.userName"
        ></el-input>
      </el-form-item>
      <el-form-item label="密码" prop="password">
        <el-input
          @keydown.enter.native="login"
          type="password"
          v-model="ruleForm.password"
          autocomplete="off"
        ></el-input>
      </el-form-item>
      <el-form-item>
        <el-button type="primary" 
        @click="submitForm('ruleForm')"
          >登 录</el-button
        >
        <el-button @click="resetForm('ruleForm')">重 置</el-button>
      </el-form-item>
    </el-form>
  </div>
</template>

<script>
import axios from "axios";
import {
  setUsername,
  setToken
} from "@/utils/username";
export default {
  name: "LoginView",
  data() {
    var checkUserName = (rule, value, callback) => {
      if (!value) {
        return callback(new Error("用户名不能为空"));
      }
      callback();
    };
    var validatePass = (rule, value, callback) => {
      if (value === "") {
        callback(new Error("请输入密码"));
      } else {
        if (this.ruleForm.checkPass !== "") {
          this.$refs.ruleForm.validateField("checkPass");
        }
        callback();
      }
    };

    return {
      ruleForm: {
        password: "",
        userName: "",
      },
      rules: {
        password: [{ validator: validatePass, trigger: "blur" }],
        userName: [{ validator: checkUserName, trigger: "blur" }],
      },
    };
  },
  methods: {
    login() {
      axios
        .post("http://47.99.45.73:8000/user/login", this.ruleForm)
        .then((resp) => {
          if (resp.data.code == 200) {
            //将token存入localstorage
            setToken(resp.data.token)
            //将用户名存入localStorage
            setUsername(this.ruleForm.userName);
            //路由跳转
            this.$router.push({
              name: "HomeView",
            });
            this.$message({
              message: "登录成功",
              type: "success",
            });
          } else {
            this.$message.error("用户名或密码错误");
          }
        });
    },
    submitForm(formName) {
      this.$refs[formName].validate((valid) => {
        if (valid) {
          this.login();
        } else {
          return false;
        }
      });
    },
    resetForm(formName) {
      this.$refs[formName].resetFields();
    },
  },
};
</script>
<style scoped>
.login {
  width: 500px;
  height: 300px;
  margin: auto;
  position: absolute;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
}

.login p {
  text-align: center;
}
</style>
